func TestEnumAllowedCheckPaymentStatus(t *testing.T) {
	t.Run("NewFromString_0", func(t *testing.T) {
		t.Parallel()
		val, err := NewAllowedCheckPaymentStatusFromString("0")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, AllowedCheckPaymentStatus("0"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_5", func(t *testing.T) {
		t.Parallel()
		val, err := NewAllowedCheckPaymentStatusFromString("5")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, AllowedCheckPaymentStatus("5"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewAllowedCheckPaymentStatusFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewAllowedCheckPaymentStatusFromString("0")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

